import React, { useEffect, useState } from 'react';
import { violationsAPI } from '../../services/api';
import Card from '../../components/common/Card';
import Modal from '../../components/common/Modal';
import toast from 'react-hot-toast';
import { Search, CheckCircle, Eye, Filter } from 'lucide-react';

const ManageViolations = () => {
  const [violations, setViolations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [filters, setFilters] = useState({ status: '' });
  const [showViewModal, setShowViewModal] = useState(false);
  const [showResolveModal, setShowResolveModal] = useState(false);
  const [selectedViolation, setSelectedViolation] = useState(null);
  const [resolveRemarks, setResolveRemarks] = useState('');
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetchViolations();
  }, [filters]);

  const fetchViolations = async () => {
    setLoading(true);
    try {
      const response = await violationsAPI.getAll({ ...filters, search: searchTerm });
      if (response.data.success) {
        setViolations(response.data.violations);
      }
    } catch (error) {
      console.error('Error fetching violations:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    fetchViolations();
  };

  const handleResolve = async () => {
    if (!selectedViolation) return;
    setSaving(true);
    try {
      await violationsAPI.resolve(selectedViolation.id, resolveRemarks);
      toast.success('Violation resolved');
      setShowResolveModal(false);
      setResolveRemarks('');
      fetchViolations();
    } catch (error) {
      toast.error('Failed to resolve violation');
    } finally {
      setSaving(false);
    }
  };

  const openViewModal = (violation) => {
    setSelectedViolation(violation);
    setShowViewModal(true);
  };

  const openResolveModal = (violation) => {
    setSelectedViolation(violation);
    setResolveRemarks('');
    setShowResolveModal(true);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <h1 className="text-2xl font-bold text-secondary-800">Manage Violations</h1>

      {/* Filters */}
      <Card>
        <form onSubmit={handleSearch} className="flex flex-wrap gap-4">
          <div className="flex-1 min-w-[200px] relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-secondary-400" />
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search violations..."
              className="input-field pl-10"
            />
          </div>
          <select
            value={filters.status}
            onChange={(e) => setFilters(prev => ({ ...prev, status: e.target.value }))}
            className="input-field w-auto"
          >
            <option value="">All Status</option>
            <option value="Pending">Pending</option>
            <option value="Resolved">Resolved</option>
          </select>
          <button type="submit" className="btn-primary">Search</button>
        </form>
      </Card>

      {/* Violations Table */}
      <Card>
        {loading ? (
          <div className="text-center py-10">Loading...</div>
        ) : violations.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-secondary-200">
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Student</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Violation</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Date</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Encoded By</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Status</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Actions</th>
                </tr>
              </thead>
              <tbody>
                {violations.map((violation) => (
                  <tr key={violation.id} className="border-b border-secondary-100 hover:bg-secondary-50">
                    <td className="py-3 px-4">
                      <p className="font-medium">{violation.student_first_name} {violation.student_last_name}</p>
                      <p className="text-sm text-secondary-500">{violation.student_id}</p>
                    </td>
                    <td className="py-3 px-4">{violation.violation_type}</td>
                    <td className="py-3 px-4">{violation.date}</td>
                    <td className="py-3 px-4">{violation.encoded_by_name || 'Admin'}</td>
                    <td className="py-3 px-4">
                      <span className={`px-3 py-1 rounded-full text-sm ${
                        violation.status === 'Pending'
                          ? 'bg-yellow-100 text-yellow-700'
                          : 'bg-green-100 text-green-700'
                      }`}>
                        {violation.status}
                      </span>
                    </td>
                    <td className="py-3 px-4">
                      <div className="flex items-center gap-2">
                        <button
                          onClick={() => openViewModal(violation)}
                          className="p-2 text-secondary-500 hover:bg-secondary-100 rounded"
                          title="View"
                        >
                          <Eye className="w-4 h-4" />
                        </button>
                        {violation.status === 'Pending' && (
                          <button
                            onClick={() => openResolveModal(violation)}
                            className="p-2 text-green-500 hover:bg-green-50 rounded"
                            title="Resolve"
                          >
                            <CheckCircle className="w-4 h-4" />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="text-center py-10 text-secondary-500">
            No violations found
          </div>
        )}
      </Card>

      {/* View Modal */}
      <Modal
        isOpen={showViewModal}
        onClose={() => setShowViewModal(false)}
        title="Violation Details"
      >
        {selectedViolation && (
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-sm text-secondary-500">Student</p>
                <p className="font-medium">{selectedViolation.student_first_name} {selectedViolation.student_last_name}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Student ID</p>
                <p className="font-medium">{selectedViolation.student_id}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Violation Type</p>
                <p className="font-medium">{selectedViolation.violation_type}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Date</p>
                <p className="font-medium">{selectedViolation.date}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Status</p>
                <p className="font-medium">{selectedViolation.status}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Encoded By</p>
                <p className="font-medium">{selectedViolation.encoded_by_name || 'Admin'}</p>
              </div>
              <div className="col-span-2">
                <p className="text-sm text-secondary-500">Remarks</p>
                <p className="font-medium">{selectedViolation.remarks || 'N/A'}</p>
              </div>
            </div>
          </div>
        )}
      </Modal>

      {/* Resolve Modal */}
      <Modal
        isOpen={showResolveModal}
        onClose={() => setShowResolveModal(false)}
        title="Resolve Violation"
      >
        <div className="space-y-4">
          <p>Are you sure you want to mark this violation as resolved?</p>
          <div>
            <label className="label">Resolution Remarks</label>
            <textarea
              value={resolveRemarks}
              onChange={(e) => setResolveRemarks(e.target.value)}
              rows={3}
              className="input-field"
              placeholder="Add remarks about the resolution..."
            />
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowResolveModal(false)} className="btn-secondary flex-1">
              Cancel
            </button>
            <button onClick={handleResolve} disabled={saving} className="btn-primary flex-1">
              {saving ? 'Resolving...' : 'Resolve'}
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default ManageViolations;
